import { useState, useRef } from 'react';
import { Autocomplete } from '@react-google-maps/api';
import axios from 'axios';
import '../styles/CreateDestination.css';

export default function CreateDestination({ onClose }) {
    const [name, setName] = useState('');
    const [image, setImage] = useState(null);
    const [imagePreview, setImagePreview] = useState(null);
    const [priceHouse, setPriceHouse] = useState('');
    const [priceTravel, setPriceTravel] = useState('');
    const [dates, setDates] = useState('');
    const [proposedBy, setProposedBy] = useState('');
    const [location, setLocation] = useState(null);
    const autocompleteRef = useRef(null);

    const handleImageChange = (e) => {
        const file = e.target.files[0];
        if (file) {
            const reader = new FileReader();
            reader.onloadend = () => {
                setImage(reader.result);
                setImagePreview(reader.result);
            };
            reader.readAsDataURL(file);
        }
    };

    const handlePlaceChanged = () => {
        const place = autocompleteRef.current.getPlace();
        if (place && place.geometry) {
            const loc = {
                lat: place.geometry.location.lat(),
                lng: place.geometry.location.lng(),
                address: place.formatted_address
            };
            setLocation(loc);
        }
    };

    const handleSubmit = async (e) => {
        e.preventDefault();

        const newDestination = {
            name,
            image,
            priceHouse,
            priceTravel,
            dates,
            proposedBy,
            location,
        };

        try {
            await axios.post('/api/destinations', newDestination);
            onClose(); // Fermer le modal
        } catch (error) {
            console.error("Erreur lors de la création de la destination :", error);
            alert("Une erreur est survenue lors de la création.");
        }
    };

    return (
        <form onSubmit={handleSubmit} className="destination-form">
            <h2>Créer une destination</h2>

            <label>Nom</label>
            <input type="text" value={name} onChange={(e) => setName(e.target.value)} required />

            <label>Image</label>
            <input type="file" accept="image/*" onChange={handleImageChange} />
            {imagePreview && (
                <img src={imagePreview} alt="Preview" style={{ width: '50%', margin: 'auto', borderRadius: '8px' }} />
            )}

            <label>Prix logement</label>
            <input type="text" value={priceHouse} onChange={(e) => setPriceHouse(e.target.value)} required />

            <label>Prix transport</label>
            <input type="text" value={priceTravel} onChange={(e) => setPriceTravel(e.target.value)} required />

            <label>Dates</label>
            <input type="text" value={dates} onChange={(e) => setDates(e.target.value)} required />

            <label>Proposé par</label>
            <input type="text" value={proposedBy} onChange={(e) => setProposedBy(e.target.value)} required />

            <label>Lieu</label>
            <Autocomplete
                onLoad={(auto) => (autocompleteRef.current = auto)}
                onPlaceChanged={handlePlaceChanged}
            >
                <input
                    type="text"
                    placeholder="Tapez une adresse ou ville..."
                    style={{
                        width: '100%',
                        padding: '10px',
                        fontSize: '16px',
                        borderRadius: '8px',
                        marginBottom: '10px',
                        border: '1px solid #ccc',
                    }}
                    required
                />
            </Autocomplete>

            <button type="submit" className="create-button">Créer</button>
        </form>
    );
}
